// // This module calculates the absolute value of a 32-bit signed integer. If the input number is positive, the circuit outputs its two's complement to yield the non-positive equivalent; if the input is already non-positive, it simply outputs the input value unchanged.
module top_module(
  input signed [31:0] in,
  output reg [31:0] out
);// Check the sign bit of the input number
  wire signed [31:0] sign_bit = in[31];

  // If the sign bit is 1, then the input number is negative
  wire signed [31:0] negated = ~in + 1;

  // If the input number is negative, negate the number by taking the two's complement of the number
  always @(*) begin
    if (sign_bit == 1) begin
      out = negated;
    end else begin
      out = in;
    end
  end

endmodule
